const express = require('express');
const app = express();
const pg = require('pg');

// Connect to PostgreSQL database
const pool = new pg.Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'mydatabase',
  password: 'password',
  port: 5432,
});

// CRUD operations for multiple tables
app.get('/users', async (req, res) => {
  const users = await pool.query('SELECT * FROM users');
  res.json(users.rows);
});

app.post('/users', async (req, res) => {
  const user = req.body;
  const result = await pool.query('INSERT INTO users VALUES ($1, $2)', [user.name, user.email]);
  res.json(result);
});

app.get('/users/:id', async (req, res) => {
  const id = req.params.id;
  const user = await pool.query('SELECT * FROM users WHERE id=$1', [id]);
  if (user.rows.length > 0) {
    res.json(user.rows[0]);
  } else {
    res.status(404).send('User not found');
  }
});

app.put('/users/:id', async (req, res) => {
  const id = req.params.id;
  const user = req.body;
  const result = await pool.query('UPDATE users SET name=$1, email=$2 WHERE id=$3', [user.name, user.email, id]);
  res.json(result);
});

app.delete('/users/:id', async (req, res) => {
  const id = req.params.id;
  const result = await pool.query('DELETE FROM users WHERE id=$1', [id]);
  res.json(result);
});

// Handle errors
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).send('Something broke!');
});

// Start the server
const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server started on port ${port}`);
});